import { useEffect, useRef } from 'react'
import { useLocation } from 'react-router-dom'
import { posthog, posthogEnabled } from '@/lib/posthog'
import { useAuthStore } from '@/stores/authStore'

/**
 * Captures a PostHog `$pageview` event whenever the route changes.
 * No-op when PostHog is disabled (missing VITE_POSTHOG_KEY).
 */
export function usePostHogPageview() {
  const { pathname } = useLocation()
  const prevPathname = useRef<string | null>(null)

  useEffect(() => {
    if (!posthogEnabled) return
    // Avoid duplicate capture on initial render if pathname hasn't changed
    if (prevPathname.current === pathname) return
    prevPathname.current = pathname
    posthog.capture('$pageview')
  }, [pathname])
}

/**
 * Identifies the authenticated user to PostHog when they log in,
 * and resets the PostHog identity when they log out.
 * No-op when PostHog is disabled (missing VITE_POSTHOG_KEY).
 */
export function usePostHogIdentify() {
  const user = useAuthStore((s) => s.user)

  useEffect(() => {
    if (!posthogEnabled) return

    if (user) {
      posthog.identify(user.id, { email: user.email })
    } else {
      posthog.reset()
    }
  }, [user])
}

